import base64
import zlib
from datetime import datetime, timedelta
import urllib.parse
import uuid
import requests


class SAMLServiceProvider:
    def __init__(self, issuer, acs_url):
        self.issuer = issuer
        self.acs_url = acs_url
    
    def build_authn_request(self, destination_url, user_info):
        request_id = "_" + str(uuid.uuid4())
        issue_instant = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
        
        username = user_info.get('username', '')
        email = user_info.get('email', '')
        first_name = user_info.get('first_name', '')
        last_name = user_info.get('last_name', '')
        
        saml_request = '<?xml version="1.0" encoding="UTF-8"?>'
        saml_request += '<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" '
        saml_request += 'xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" '
        saml_request += 'ID="' + request_id + '" '
        saml_request += 'Version="2.0" '
        saml_request += 'IssueInstant="' + issue_instant + '" '
        saml_request += 'Destination="' + destination_url + '" '
        saml_request += 'AssertionConsumerServiceURL="' + self.acs_url + '" '
        saml_request += 'ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">'
        saml_request += '<saml:Issuer>' + self.issuer + '</saml:Issuer>'
        saml_request += '<samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>'
        
        if username or email or first_name or last_name:
            saml_request += '<saml:AttributeStatement>'
            if username:
                saml_request += '<saml:Attribute Name="username"><saml:AttributeValue>' + username + '</saml:AttributeValue></saml:Attribute>'
            if email:
                saml_request += '<saml:Attribute Name="email"><saml:AttributeValue>' + email + '</saml:AttributeValue></saml:Attribute>'
            if first_name:
                saml_request += '<saml:Attribute Name="firstName"><saml:AttributeValue>' + first_name + '</saml:AttributeValue></saml:Attribute>'
            if last_name:
                saml_request += '<saml:Attribute Name="lastName"><saml:AttributeValue>' + last_name + '</saml:AttributeValue></saml:Attribute>'
            saml_request += '</saml:AttributeStatement>'
        
        saml_request += '</samlp:AuthnRequest>'
        
        return saml_request
    
    def encode_saml_request(self, saml_request):
        compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')
        return encoded
    
    def send_authn_request(self, destination_url, user_info, relay_state=None):
        saml_request = self.build_authn_request(destination_url, user_info)
        encoded_request = self.encode_saml_request(saml_request)
        
        post_data = {
            'SAMLRequest': encoded_request
        }
        
        if relay_state:
            post_data['RelayState'] = relay_state
        
        response = requests.post(destination_url, data=post_data)
        
        return {
            'status_code': response.status_code,
            'response': response.text,
            'saml_request': saml_request,
            'encoded_request': encoded_request
        }
    
    def send_authn_request_redirect(self, destination_url, user_info, relay_state=None):
        saml_request = self.build_authn_request(destination_url, user_info)
        encoded_request = self.encode_saml_request(saml_request)
        
        params = {
            'SAMLRequest': encoded_request
        }
        
        if relay_state:
            params['RelayState'] = relay_state
        
        query_string = urllib.parse.urlencode(params)
        redirect_url = destination_url + '?' + query_string
        
        return {
            'redirect_url': redirect_url,
            'saml_request': saml_request,
            'encoded_request': encoded_request
        }


